#pragma once

#include <cuda_runtime.h>
#include <stdint.h>
#include <cuda_bf16.h>

// Kernel launch configuration
#define BLOCK_SIZE 256
#define HEAD_SIZE 128
#define NUM_V_HEADS 16
#define NUM_Q_HEADS 8
#define NUM_K_HEADS 8

// Kernel declaration
__global__ void gdn_prefill_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const float* __restrict__ state,
    float* __restrict__ new_state,
    const float* __restrict__ A_log,
    const __nv_bfloat16* __restrict__ a,
    const float* __restrict__ dt_bias,
    const __nv_bfloat16* __restrict__ b,
    const __nv_bfloat16* __restrict__ output,
    const int64_t* __restrict__ cu_seqlens,
    float scale,
    int64_t total_seq_len,
    int64_t num_seqs,
    int64_t len_cu_seqlens
);

// Host function declaration
void launch_gdn_prefill(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const float* state,
    float* new_state,
    const float* A_log,
    const __nv_bfloat16* a,
    const float* dt_bias,
    const __nv_bfloat16* b,
    __nv_bfloat16* output,
    const int64_t* cu_seqlens,
    float scale,
    int64_t total_seq_len,
    int64_t num_seqs,
    int64_t len_cu_seqlens
);

#include "kernel.h"
#include <math.h>

__global__ void gdn_prefill_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const float* __restrict__ state,
    float* __restrict__ new_state,
    const float* __restrict__ A_log,
    const __nv_bfloat16* __restrict__ a,
    const float* __restrict__ dt_bias,
    const __nv_bfloat16* __restrict__ b,
    const __nv_bfloat16* __restrict__ output,
    const int64_t* __restrict__ cu_seqlens,
    float scale,
    int64_t total_seq_len,
    int64_t num_seqs,
    int64_t len_cu_seqlens
) {
    // Shared memory
    __shared__ float state_shared[HEAD_SIZE][HEAD_SIZE];
    __shared__ __nv_bfloat16 k_shared[HEAD_SIZE];
    __shared__ __nv_bfloat16 v_shared[HEAD_SIZE];
    __shared__ __nv_bfloat16 q_shared[HEAD_SIZE];
    __shared__ float proj_shared[HEAD_SIZE];
    __shared__ float diff_shared[HEAD_SIZE];
    __shared__ __nv_bfloat16 out_shared[HEAD_SIZE];

    int tid = threadIdx.x;
    int v_idx = tid / 2;
    int lane = tid % 2;

    // Identify sequence and head
    int64_t seq_idx = blockIdx.x / NUM_V_HEADS;
    int64_t head_idx = blockIdx.x % NUM_V_HEADS;

    // Bounds check
    if (seq_idx >= num_seqs) return;

    // Load sequence bounds
    int64_t seq_start = 0;
    int64_t seq_end = 0;
    if (lane == 0) {
        seq_start = cu_seqlens[seq_idx];
        seq_end = cu_seqlens[seq_idx + 1];
    }
    __syncthreads();
    seq_start = __shfl_sync(0xffffffff, seq_start, 0);
    seq_end = __shfl_sync(0xffffffff, seq_end, 0);

    int64_t seq_len = seq_end - seq_start;
    if (seq_len <= 0) return;

    // Load head-specific parameters
    float A_log_val = 0.0f;
    float dt_bias_val = 0.0f;
    if (lane == 0) {
        A_log_val = A_log[head_idx];
        dt_bias_val = dt_bias[head_idx];
    }
    __syncthreads();
    A_log_val = __shfl_sync(0xffffffff, A_log_val, 0);
    dt_bias_val = __shfl_sync(0xffffffff, dt_bias_val, 0);

    // Load initial state
    const float* state_ptr = state + seq_idx * NUM_V_HEADS * HEAD_SIZE * HEAD_SIZE + head_idx * HEAD_SIZE * HEAD_SIZE;
    for (int k_idx = lane * 64; k_idx < HEAD_SIZE; k_idx += 1) {
        state_shared[v_idx][k_idx] = state_ptr[v_idx * HEAD_SIZE + k_idx];
    }
    __syncthreads();

    // Loop over tokens
    for (int64_t t = seq_start; t < seq_end; t++) {
        // Compute g and beta
        float a_val = 0.0f;
        float b_val = 0.0f;
        if (lane == 0) {
            a_val = __bfloat162float(a[t * NUM_V_HEADS + head_idx]);
            b_val = __bfloat162float(b[t * NUM_V_HEADS + head_idx]);
        }
        __syncthreads();
        a_val = __shfl_sync(0xffffffff, a_val, 0);
        b_val = __shfl_sync(0xffffffff, b_val, 0);

        float g = expf(-expf(A_log_val) * log1pf(expf(a_val + dt_bias_val)));
        float beta = 1.0f / (1.0f + expf(-b_val));

        // Load k, v, q
        int64_t q_head = head_idx / 2;
        int64_t k_head = head_idx / 2;
        int64_t v_head = head_idx;

        const __nv_bfloat16* q_ptr = q + t * NUM_Q_HEADS * HEAD_SIZE + q_head * HEAD_SIZE;
        const __nv_bfloat16* k_ptr = k + t * NUM_K_HEADS * HEAD_SIZE + k_head * HEAD_SIZE;
        const __nv_bfloat16* v_ptr = v + t * NUM_V_HEADS * HEAD_SIZE + v_head * HEAD_SIZE;

        for (int k_idx = lane * 64; k_idx < HEAD_SIZE; k_idx += 1) {
            q_shared[k_idx] = q_ptr[k_idx];
            k_shared[k_idx] = k_ptr[k_idx];
        }
        if (v_idx < HEAD_SIZE) {
            v_shared[v_idx] = v_ptr[v_idx];
        }
        __syncthreads();

        // Compute proj = k @ state
        // proj[v_idx] = sum_k k[k_idx] * state[v_idx][k_idx]
        float proj = 0.0f;
        for (int k_idx = lane * 64; k_idx < HEAD_SIZE; k_idx += 1) {
            float k_val = __bfloat162float(k_shared[k_idx]);
            float s_val = state_shared[v_idx][k_idx];
            proj += k_val * s_val;
        }
        // Reduce across lanes
        if (lane == 1) {
            proj = __shfl_sync(0xffffffff, proj, 0);
        }
        if (lane == 0) {
            proj_shared[v_idx] = proj;
        }
        __syncthreads();

        // Compute diff = v - proj
        float v_val = __bfloat162float(v_shared[v_idx]);
        float proj_val = proj_shared[v_idx];
        float diff = v_val - proj_val;
        if (lane == 0) {
            diff_shared[v_idx] = diff;
        }
        __syncthreads();

        // Update state
        // state[v_idx][k_idx] = g * state[v_idx][k_idx] + beta * k[k_idx] * diff
        float diff_val = diff_shared[v_idx];
        for (int k_idx = lane * 64; k_idx < HEAD_SIZE; k_idx += 1) {
            float k_val = __bfloat162float(k_shared[k_idx]);
            float s_val = state_shared[v_idx][k_idx];
            state_shared[v_idx][k_idx] = g * s_val + beta * k_val * diff_val;
        }
        __syncthreads();

        // Compute output = scale * q @ state
        // out[v_idx] = sum_k q[k_idx] * state[v_idx][k_idx]
        float out = 0.0f;
        for (int k_idx = lane * 64; k_idx < HEAD_SIZE; k_idx += 1) {
            float q_val = __bfloat162float(q_shared[k_idx]);
            float s_val = state_shared[v_idx][k_idx];
            out += q_val * s_val;
        }
        // Reduce across lanes
        if (lane == 1) {
            out = __shfl_sync(0xffffffff, out, 0);
        }
        if (lane == 0) {
            out_shared[v_idx] = __float2bfloat16(scale * out);
        }
        __syncthreads();

        // Store output
        __nv_bfloat16* output_ptr = const_cast<__nv_bfloat16*>(output) + t * NUM_V_HEADS * HEAD_SIZE + head_idx * HEAD_SIZE;
        if (v_idx < HEAD_SIZE) {
            output_ptr[v_idx] = out_shared[v_idx];
        }
    }

    // Store final state
    float* new_state_ptr = new_state + seq_idx * NUM_V_HEADS * HEAD_SIZE * HEAD_SIZE + head_idx * HEAD_SIZE * HEAD_SIZE;
    for (int k_idx = lane * 64; k_idx < HEAD_SIZE; k_idx += 1) {
        new_state_ptr[v_idx * HEAD_SIZE + k_idx] = state_shared[v_idx][k_idx];
    }
}

void launch_gdn_prefill(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const float* state,
    float* new_state,
    const float* A_log,
    const __nv_bfloat16* a,
    const float* dt_bias,
    const __nv_bfloat16* b,
    __nv_bfloat16* output,
    const int64_t* cu_seqlens,
    float scale,
    int64_t total_seq_len,
    int64_t num_seqs,
    int64_t len_cu_seqlens
) {
    dim3 grid(num_seqs * NUM_V_HEADS);
    dim3 block(BLOCK_SIZE);
    gdn_prefill_kernel<<<grid, block>>>(
        q, k, v, state, new_state, A_log, a, dt_bias, b, output, cu_seqlens, scale,
        total_seq_len, num_seqs, len_cu_seqlens
    );
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        printf("CUDA Error: %s\n", cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include "kernel.h"
#include <cmath>

std::tuple<torch::Tensor, torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    torch::Tensor cu_seqlens,
    float scale
) {
    // Validate device
    if (!q.is_cuda() || !k.is_cuda() || !v.is_cuda() || !state.is_cuda() ||
        !A_log.is_cuda() || !a.is_cuda() || !dt_bias.is_cuda() || !b.is_cuda() || !cu_seqlens.is_cuda()) {
        throw std::runtime_error("All inputs must be on CUDA");
    }

    // Validate dtypes
    if (q.dtype() != torch::kBFloat16 || k.dtype() != torch::kBFloat16 || v.dtype() != torch::kBFloat16 ||
        a.dtype() != torch::kBFloat16 || b.dtype() != torch::kBFloat16) {
        throw std::runtime_error("q, k, v, a, b must be bfloat16");
    }
    if (state.dtype() != torch::kFloat32 || A_log.dtype() != torch::kFloat32 || dt_bias.dtype() != torch::kFloat32) {
        throw std::runtime_error("state, A_log, dt_bias must be float32");
    }
    if (cu_seqlens.dtype() != torch::kInt64) {
        throw std::runtime_error("cu_seqlens must be int64");
    }

    // Validate shapes
    int64_t total_seq_len = q.size(0);
    int64_t num_q_heads = q.size(1);
    int64_t head_size = q.size(2);
    int64_t num_k_heads = k.size(1);
    int64_t num_v_heads = v.size(1);
    int64_t num_seqs = cu_seqlens.size(0) - 1;
    int64_t len_cu_seqlens = cu_seqlens.size(0);

    if (num_q_heads != NUM_Q_HEADS || num_k_heads != NUM_K_HEADS || num_v_heads != NUM_V_HEADS || head_size != HEAD_SIZE) {
        throw std::runtime_error("Invalid head configuration");
    }
    if (state.size(0) != num_seqs || state.size(1) != num_v_heads || state.size(2) != head_size || state.size(3) != head_size) {
        throw std::runtime_error("Invalid state shape");
    }
    if (A_log.size(0) != num_v_heads || dt_bias.size(0) != num_v_heads) {
        throw std::runtime_error("Invalid A_log or dt_bias shape");
    }
    if (a.size(0) != total_seq_len || a.size(1) != num_v_heads || b.size(0) != total_seq_len || b.size(1) != num_v_heads) {
        throw std::runtime_error("Invalid a or b shape");
    }
    if (len_cu_seqlens != num_seqs + 1) {
        throw std::runtime_error("Invalid cu_seqlens length");
    }
    if (total_seq_len != cu_seqlens[num_seqs].item<int64_t>()) {
        throw std::runtime_error("Invalid total_seq_len");
    }

    // Create output tensors
    torch::Tensor output = torch::empty({total_seq_len, num_v_heads, head_size}, torch::TensorOptions().dtype(torch::kBFloat16).device(q.device()));
    torch::Tensor new_state = torch::empty({num_seqs, num_v_heads, head_size, head_size}, torch::TensorOptions().dtype(torch::kFloat32).device(q.device()));

    // Launch kernel
    launch_gdn_prefill(
        q.data_ptr<__nv_bfloat16>(),
        k.data_ptr<__nv_bfloat16>(),
        v.data_ptr<__nv_bfloat16>(),
        state.data_ptr<float>(),
        new_state.data_ptr<float>(),
        A_log.data_ptr<float>(),
        a.data_ptr<__nv_bfloat16>(),
        dt_bias.data_ptr<float>(),
        b.data_ptr<__nv_bfloat16>(),
        output.data_ptr<__nv_bfloat16>(),
        cu_seqlens.data_ptr<int64_t>(),
        scale,
        total_seq_len,
        num_seqs,
        len_cu_seqlens
    );

    // Synchronize and check errors
    cudaDeviceSynchronize();
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA Error: ") + cudaGetErrorString(err));
    }

    return std::make_tuple(output, new_state);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GDN Prefill Kernel");
}
